def {{nama_fungsi}}(iterable, size):
    """Yield chunks."""
    it = iter(iterable)
    while True:
        chunk = []
        try:
            for _ in range(size):
                chunk.append(next(it))
        except StopIteration:
            if chunk:
                yield chunk
            break
        yield chunk

def {{nama_fungsi}}(items):
    """Flatten nested lists/tuples."""
    for x in items:
        if isinstance(x, (list, tuple)):
            yield from {{nama_fungsi}}(x)
        else:
            yield x

def {{nama_fungsi}}(iterable, batch_size={{batch_size}}, func=lambda x: x):
    """Process iterable in batches."""
    batch = []
    for item in iterable:
        batch.append(item)
        if len(batch) >= batch_size:
            yield [func(x) for x in batch]
            batch = []
    if batch:
        yield [func(x) for x in batch]

def {{nama_fungsi}}(iterable, predicate):
    """Yield sampai predicate(item) True."""
    for item in iterable:
        if predicate(item):
            break
        yield item

def {{nama_fungsi}}(*iterables):
    """Interleave multiple iterables."""
    from itertools import zip_longest
    sentinel = object()
    for group in zip_longest(*iterables, fillvalue=sentinel):
        for item in group:
            if item is not sentinel:
                yield item

def {{nama_fungsi}}(iterable):
    """Yield unique items preserving order."""
    seen = set()
    for item in iterable:
        if item not in seen:
            seen.add(item)
            yield item

def {{nama_fungsi}}(iterable):
    """Yield (a,b) sliding pairs."""
    it = iter(iterable)
    try:
        prev = next(it)
    except StopIteration:
        return
    for cur in it:
        yield (prev, cur)
        prev = cur

def {{nama_fungsi}}(iterable, n, default=None):
    """Ambil elemen ke-n (0-indexed)."""
    import itertools
    return next(itertools.islice(iterable, n, None), default)
